{"code": "import json
from statistics import mean

# Load ratings data from file
ratings_file = locals()['var_functions.query_db:28']
if isinstance(ratings_file, str):
    with open(ratings_file, 'r') as f:
        reviews = json.load(f)
else:
    reviews = ratings_file

# Extract ratings (they're strings, need conversion)
ratings = []
for rev in reviews:
    rating_val = rev.get('rating')
    if rating_val:
        try:
            ratings.append(int(rating_val))
        except ValueError:
            continue

avg_rating = mean(ratings) if ratings else 0

print('__RESULT__:')
print(json.dumps({
    "total_reviews": len(ratings),
    "average_rating": round(avg_rating, 2)
}))
"}

